import { useCallback, useEffect, useSyncExternalStore } from "react";
import { type Theme, getTheme, listThemes } from "@t3tools/shared/themes";

export type { Theme };

const STORAGE_KEY = "t3code:theme";
const DEFAULT_THEME_ID = "t3-dark";

let listeners: Array<() => void> = [];
let lastSnapshot: Theme | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStored(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw && getTheme(raw)) return raw;
  return DEFAULT_THEME_ID;
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const isDark = theme.colorScheme === "dark";
  document.documentElement.classList.toggle("dark", isDark);
  document.documentElement.style.setProperty("color-scheme", theme.colorScheme);

  // Map theme colors onto the CSS custom properties consumed by existing Tailwind utilities
  document.documentElement.style.setProperty("--background", theme.colors.background);
  document.documentElement.style.setProperty("--foreground", theme.colors.foreground);
  document.documentElement.style.setProperty("--primary", theme.colors.accent);
  document.documentElement.style.setProperty("--ring", theme.colors.accent);

  // Theme-specific surface slots (new, available for components via CSS var)
  document.documentElement.style.setProperty("--theme-sidebar", theme.colors.sidebar);
  document.documentElement.style.setProperty("--theme-editor", theme.colors.editor);
  document.documentElement.style.setProperty("--theme-terminal", theme.colors.terminal);
  document.documentElement.style.setProperty("--theme-status-bar", theme.colors.statusBar);
  document.documentElement.style.setProperty("--theme-font-family", theme.fontFamily);
  document.documentElement.style.setProperty("--theme-font-size", `${theme.fontSize}px`);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getTheme(getStored()) ?? listThemes()[0]);

function getSnapshot(): Theme {
  const id = getStored();
  const theme = getTheme(id) ?? listThemes()[0];

  if (lastSnapshot && lastSnapshot.id === theme.id) {
    return lastSnapshot;
  }

  lastSnapshot = theme;
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      const theme = getTheme(getStored()) ?? listThemes()[0];
      applyTheme(theme, true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const resolvedTheme: "light" | "dark" = theme.colorScheme;

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id) ?? listThemes()[0];
    localStorage.setItem(STORAGE_KEY, next.id);
    applyTheme(next, true);
    emitChange();
  }, []);

  const availableThemes = listThemes();

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, availableThemes, resolvedTheme } as const;
}

